function extractRecentErrors(logFilePath, entryCount) {
    // Validate entryCount
    const count = parseInt(entryCount, 10);
    if (isNaN(count) || count <= 0) {
        throw new Error('entryCount must be a positive integer');
    }

    // Escape single quotes in the file path
    const escapedLogFilePath = logFilePath.replace(/'/g, "'\\''");

    // Construct the command
    const command = `grep 'ERROR' '${escapedLogFilePath}' | tail -n 100 | sort | tail -n ${count}`;

    // Execute the command silently
    const result = shell.exec(command, { silent: true });

    // Check for command execution errors
    if (result.code !== 0) {
        throw new Error(`Command failed: ${result.stderr}`);
    }

    // Split the output into lines and return as array
    const output = result.stdout.trim();
    return output ? output.split('\n') : [];
}

module.exports = { extractRecentErrors };
